SELECT upgrade.upgrade, upgrade.applicability, count(*) AS count FROM (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade != 0) AS upgrade JOIN (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade = 0) AS baseline ON baseline.bldg_id = upgrade.bldg_id WHERE baseline.applicability = true GROUP BY 1, 2 ORDER BY 1, 2